const fs = require('fs');
const path = '/tmp/lead_queue.json';
let q = { cycles: 0, leads: [] };
try {
  const raw = fs.readFileSync(path, 'utf8');
  q = JSON.parse(raw);
} catch(e) {
  return { qualified: [], message: 'No queue file yet' };
}

const newLeads = q.leads.filter(l => l.status === 'new' && (l.score || 0) >= 50);
newLeads.sort((a,b) => (b.score||0) - (a.score||0));
const top = newLeads.slice(0, 3);

// Mark as processing
for (const lead of top) {
  const idx = q.leads.findIndex(l => l.id === lead.id);
  if (idx !== -1) q.leads[idx].status = 'processing';
}

fs.writeFileSync(path, JSON.stringify(q, null, 2));

if (top.length === 0) {
  return { qualified: [], message: 'No qualified new leads' };
}

return {
  qualified: top.map(l => ({
    business_name: l.business_name,
    email: l.email,
    phone: l.phone,
    industry: l.industry,
    score: l.score,
    website: l.website
  })),
  message: `Qualified ${top.length} leads`
};
